@@ -1554,6 +1554,20 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return Shl;
   }

+  // add (umax X, C), -C --> usub.sat(X, C)
+  // add -C, (umax X, C) --> usub.sat(X, C)
+  const APInt *C, *NegC;
+  Value *X;
+  if (match(LHS, m_OneUse(m_UMax(m_Value(X), m_APInt(C)))) &&
+      match(RHS, m_APInt(NegC)) && *NegC == -*C)
+    return replaceInstUsesWith(
+        I, Builder.CreateIntrinsic(Intrinsic::usub_sat, {Ty}, {X, ConstantInt::get(Ty, *C)}));
+  if (match(RHS, m_OneUse(m_UMax(m_Value(X), m_APInt(C)))) &&
+      match(LHS, m_APInt(NegC)) && *NegC == -*C)
+    return replaceInstUsesWith(
+        I, Builder.CreateIntrinsic(Intrinsic::usub_sat, {Ty}, {X, ConstantInt::get(Ty, *C)}));
+
+
